  return _story(
    team: team,
    appAccountToken: 'teamId',
    webOrderLineItemId: 'apple-1',
  );
}

@GenerateScenario()
Widget subscribedByMe(BuildContext context) {
  final team = _team(teamPlan: _activeTeamPlanApple());
  return _story(
    team: team,
    appAccountToken: 'teamId',
    webOrderLineItemId: 'apple-1',
  );
}

@GenerateScenario()
Widget subscribedByMeInOtherTeam(BuildContext context) {
  final team = _team(teamPlan: _activeTeamPlanApple());
  return _story(
    team: team,
    appAccountToken: 'another-team-id',
    webOrderLineItemId: 'apple-1',
  );
}

@GenerateScenario()
Widget subscribedOnWeb(BuildContext context) {
  final team = _team(teamPlan: _activeTeamPlanStripe());
  return _story(team: team);
}

@GenerateScenario()
Widget subscribedByTeammate(BuildContext context) {
  final team = _team(teamPlan: _activeTeamPlanApple());
  return _story(team: team);
}

@GenerateScenario()
Widget notSubscribedOrCancelled(BuildContext context) {
  // 期限切れのプランを持つ（canAnalyze=false）→ notSubscribed だが Card は表示される
  final team = _team(teamPlan: _expiredTeamPlan());
  return _story(team: team);
}

@GenerateScenario()
Widget autoRenewFailed(BuildContext context) {
  final team = _team(teamPlan: _expiredTeamPlan())
      .copyWith(billingFailureReason: 'payment_failed');
  return _story(team: team);
}

// AI コーチ使用状況の表示テスト用シナリオ
@GenerateScenario()
Widget aiCoachUsageNearLimit(BuildContext context) {
  final planWithAiCoach = _basePlan.copyWith(maxAiCoachs: 10);
  final teamPlan = _activeTeamPlanApple().copyWith(
    plan: planWithAiCoach,
    currentAiCoachUsage: 9, // 90% 使用 (警告色表示テスト)
  );
  final team = _team(teamPlan: teamPlan);
  return _story(
    team: team,
    appAccountToken: 'teamId',
    webOrderLineItemId: 'apple-1',
  );
}

@GenerateScenario()
Widget aiCoachUsageHalfway(BuildContext context) {
  final planWithAiCoach = _basePlan.copyWith(maxAiCoachs: 30);
  final teamPlan = _activeTeamPlanStripe().copyWith(
    plan: planWithAiCoach,
    currentAiCoachUsage: 15, // 50% 使用
  );
  final team = _team(teamPlan: teamPlan);
  return _story(team: team);
}

@GenerateScenario()
Widget aiCoachUsageZero(BuildContext context) {
  final planWithAiCoach = _basePlan.copyWith(maxAiCoachs: 5);
  final teamPlan = _activeTeamPlanApple().copyWith(
    plan: planWithAiCoach,
    currentAiCoachUsage: 0, // 0% 使用
  );
  final team = _team(teamPlan: teamPlan);
  return _story(
    team: team,
    appAccountToken: 'teamId',
    webOrderLineItemId: 'apple-1',
  );
}

@GenerateScenario()
Widget noAiCoachPlan(BuildContext context) {
  final planWithoutAiCoach = _basePlan.copyWith(maxAiCoachs: 0);
  final teamPlan = _activeTeamPlanApple().copyWith(
    plan: planWithoutAiCoach,
    currentAiCoachUsage: 0,
  );
  final team = _team(teamPlan: teamPlan);
  return _story(
    team: team,
    appAccountToken: 'teamId',
    webOrderLineItemId: 'apple-1',
  );
}

// 共通のProvider上書き＋PlanCard描画
Widget _story({
  required Team team,
  String? appAccountToken,
  String? webOrderLineItemId,
}) {
  return ProviderScope(
    overrides: [
      teamListControllerProvider.overrideWith(
        () => FakeTeamListController(result: Right([team])),
      ),
      subscriptionControllerProvider.overrideWith(
        () => FakeSubscriptionController(
          appAccountToken: appAccountToken,
          webOrderLineItemId: webOrderLineItemId,
        ),
      ),
    ],
    child: PlanCard(teamList: [team]),
  );
}

