   100→  ResourceData _reprocessResource(
   101→    ResourceData resource,
   102→    String teamId,
   103→    String sessionId,
   104→    String? userId,
   105→  ) {
   106→    return resource.copyWith(
   107→      teamId: teamId,
   108→      sessionId: sessionId,
   109→      userId: userId ?? resource.userId,
   110→    );
   111→  }
   112→
   113→  ResourceData _reprocessResourceWithBallInfo(
   114→    ResourceData resource,
   115→    String teamId,
   116→    String sessionId,
   117→    String? userId,
   118→  ) {
   119→    final ballInfoList = resource.ballInfoList!.toList()
   120→      ..retainWhere((ballInfo) =>
   121→          (ballInfo.ball.isPitched ?? false) || (ballInfo.ball.isHit ?? false));
   122→
   123→    return _reprocessResource(
   124→      resource.copyWith(ballInfoList: ballInfoList),
   125→      teamId,
   126→      sessionId,
   127→      userId,
   128→    );
   129→  }
