    12→String usePlanNameFromPlanType(PlanType? planType) {
    13→  final context = useContext();
    14→
    15→  if (planType == null) return '';
    16→
    17→  return useMemoized(
    18→      () => switch (planType) {
    19→            PlanType.light => context.l10n.subscription_page__plan_light,
    20→            PlanType.standard => context.l10n.subscription_page__plan_standard,
    21→            PlanType.premium => context.l10n.subscription_page__plan_premium,
    22→            PlanType.forMultipleTeam => '',
    23→          },
    24→      [planType]);
    25→}
    26→
    27→String usePlanNameFromTeamPlan(TeamPlan? teamPlan) {
    28→  final context = useContext();
    29→  return teamPlan?.plan?.name == null
    30→      ? context.l10n.settings_page__no_plan_name
    31→      : switch (PlanType.fromName(teamPlan!.plan!.name!)) {
    32→          PlanType.light => context.l10n.subscription_page__plan_light,
    33→          PlanType.standard => context.l10n.subscription_page__plan_standard,
    34→          PlanType.premium => context.l10n.subscription_page__plan_premium,
    35→          PlanType.forMultipleTeam =>
    36→            teamPlan.plan?.name ?? context.l10n.settings_page__no_plan_name,
    37→        };
    38→}
    39→
    40→String? usePlanNameFromPlanId(String? id) {
    41→  final context = useContext();
    42→  final ref = useWidgetRef();
    43→  final plans = ref.watch(plansControllerProvider);
    44→  return plans.map(
    45→    error: (_) => null,
    46→    loading: (_) => null,
    47→    data: (data) {
    48→      final matchedPlan =
    49→          data.value.firstWhereOrNull((e) => e.id != null && e.id == id);
    50→
    51→      if (matchedPlan?.name == null) return null;
    52→
    53→      final planType = PlanType.fromName(matchedPlan!.name!);
    54→      return switch (planType) {
